import{_ as t,o as r,c as a,a2 as o}from"./chunks/framework.jisAoZJG.js";const k=JSON.parse('{"title":"Interface: SkillStorage","description":"","frontmatter":{"head":[["link",{"rel":"canonical","href":"https://sqlrooms.org/api/ai/interfaces/SkillStorage.html"}]]},"headers":[],"relativePath":"api/ai/interfaces/SkillStorage.md","filePath":"api/ai/interfaces/SkillStorage.md"}'),l={name:"api/ai/interfaces/SkillStorage.md"};function d(i,e,s,h,c,n){return r(),a("div",null,[...e[0]||(e[0]=[o('<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /api/ai/interfaces/SkillStorage.md for this page in Markdown format</div><p><a href="./../">@sqlrooms/ai</a> / SkillStorage</p><h1 id="interface-skillstorage" tabindex="-1">Interface: SkillStorage <a class="header-anchor" href="#interface-skillstorage" aria-label="Permalink to &quot;Interface: SkillStorage&quot;">​</a></h1><p>Abstract storage backend for skills. Implementations may be filesystem, in-memory, HTTP, OPFS, etc. All operations are Promise-based.</p><p>Priority is encoded in the order returned by <code>listRoots()</code>: earlier roots override later ones for <code>resolveSkillId</code> conflict resolution.</p><h2 id="methods" tabindex="-1">Methods <a class="header-anchor" href="#methods" aria-label="Permalink to &quot;Methods&quot;">​</a></h2><h3 id="listroots" tabindex="-1">listRoots() <a class="header-anchor" href="#listroots" aria-label="Permalink to &quot;listRoots()&quot;">​</a></h3><blockquote><p><strong>listRoots</strong>(): <code>Promise</code>&lt;<a href="./SkillRoot.html"><code>SkillRoot</code></a>[]&gt;</p></blockquote><p>Enumerate all roots known to this storage, in priority order (highest priority first).</p><h4 id="returns" tabindex="-1">Returns <a class="header-anchor" href="#returns" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>Promise</code>&lt;<a href="./SkillRoot.html"><code>SkillRoot</code></a>[]&gt;</p><hr><h3 id="listskills" tabindex="-1">listSkills() <a class="header-anchor" href="#listskills" aria-label="Permalink to &quot;listSkills()&quot;">​</a></h3><blockquote><p><strong>listSkills</strong>(<code>rootId?</code>): <code>Promise</code>&lt;<a href="./SkillListing.html"><code>SkillListing</code></a>[]&gt;</p></blockquote><p>List skills. If <code>rootId</code> is provided, returns only skills from that root. When called without a rootId, returns skills from every root; duplicates (same <code>id</code> in multiple roots) are included so callers can render conflict indicators.</p><h4 id="parameters" tabindex="-1">Parameters <a class="header-anchor" href="#parameters" aria-label="Permalink to &quot;Parameters&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Parameter</th><th>Type</th></tr></thead><tbody><tr><td><code>rootId?</code></td><td><code>string</code></td></tr></tbody></table><h4 id="returns-1" tabindex="-1">Returns <a class="header-anchor" href="#returns-1" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>Promise</code>&lt;<a href="./SkillListing.html"><code>SkillListing</code></a>[]&gt;</p><hr><h3 id="readskill" tabindex="-1">readSkill() <a class="header-anchor" href="#readskill" aria-label="Permalink to &quot;readSkill()&quot;">​</a></h3><blockquote><p><strong>readSkill</strong>(<code>ref</code>): <code>Promise</code>&lt;<a href="./SkillRecord.html"><code>SkillRecord</code></a>&gt;</p></blockquote><p>Read the full record for a single skill.</p><h4 id="parameters-1" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-1" aria-label="Permalink to &quot;Parameters&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Parameter</th><th>Type</th></tr></thead><tbody><tr><td><code>ref</code></td><td><a href="./SkillRef.html"><code>SkillRef</code></a></td></tr></tbody></table><h4 id="returns-2" tabindex="-1">Returns <a class="header-anchor" href="#returns-2" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>Promise</code>&lt;<a href="./SkillRecord.html"><code>SkillRecord</code></a>&gt;</p><h4 id="throws" tabindex="-1">Throws <a class="header-anchor" href="#throws" aria-label="Permalink to &quot;Throws&quot;">​</a></h4><p>a <code>SkillNotFoundError</code> if the ref does not resolve.</p><h4 id="throws-1" tabindex="-1">Throws <a class="header-anchor" href="#throws-1" aria-label="Permalink to &quot;Throws&quot;">​</a></h4><p>a <code>SkillManifestError</code> if the skill&#39;s <code>skill.yaml</code> fails to parse or validate.</p><hr><h3 id="writeskill" tabindex="-1">writeSkill() <a class="header-anchor" href="#writeskill" aria-label="Permalink to &quot;writeSkill()&quot;">​</a></h3><blockquote><p><strong>writeSkill</strong>(<code>rootId</code>, <code>id</code>, <code>content</code>): <code>Promise</code>&lt;<a href="./SkillRef.html"><code>SkillRef</code></a>&gt;</p></blockquote><p>Create or overwrite a skill in the given root. Returns the resulting ref.</p><h4 id="parameters-2" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-2" aria-label="Permalink to &quot;Parameters&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Parameter</th><th>Type</th></tr></thead><tbody><tr><td><code>rootId</code></td><td><code>string</code></td></tr><tr><td><code>id</code></td><td><code>string</code></td></tr><tr><td><code>content</code></td><td><a href="./SkillWriteContent.html"><code>SkillWriteContent</code></a></td></tr></tbody></table><h4 id="returns-3" tabindex="-1">Returns <a class="header-anchor" href="#returns-3" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>Promise</code>&lt;<a href="./SkillRef.html"><code>SkillRef</code></a>&gt;</p><h4 id="throws-2" tabindex="-1">Throws <a class="header-anchor" href="#throws-2" aria-label="Permalink to &quot;Throws&quot;">​</a></h4><p>a <code>SkillRootReadOnlyError</code> if the target root is not writable.</p><hr><h3 id="deleteskill" tabindex="-1">deleteSkill() <a class="header-anchor" href="#deleteskill" aria-label="Permalink to &quot;deleteSkill()&quot;">​</a></h3><blockquote><p><strong>deleteSkill</strong>(<code>ref</code>): <code>Promise</code>&lt;<code>void</code>&gt;</p></blockquote><p>Remove a skill from its root.</p><h4 id="parameters-3" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-3" aria-label="Permalink to &quot;Parameters&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Parameter</th><th>Type</th></tr></thead><tbody><tr><td><code>ref</code></td><td><a href="./SkillRef.html"><code>SkillRef</code></a></td></tr></tbody></table><h4 id="returns-4" tabindex="-1">Returns <a class="header-anchor" href="#returns-4" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>Promise</code>&lt;<code>void</code>&gt;</p><h4 id="throws-3" tabindex="-1">Throws <a class="header-anchor" href="#throws-3" aria-label="Permalink to &quot;Throws&quot;">​</a></h4><p>a <code>SkillRootReadOnlyError</code> if the ref&#39;s root is not writable.</p><h4 id="throws-4" tabindex="-1">Throws <a class="header-anchor" href="#throws-4" aria-label="Permalink to &quot;Throws&quot;">​</a></h4><p>a <code>SkillNotFoundError</code> if the ref does not resolve.</p><hr><h3 id="resolveskillid" tabindex="-1">resolveSkillId() <a class="header-anchor" href="#resolveskillid" aria-label="Permalink to &quot;resolveSkillId()&quot;">​</a></h3><blockquote><p><strong>resolveSkillId</strong>(<code>id</code>): <code>Promise</code>&lt;<a href="./SkillRef.html"><code>SkillRef</code></a> | <code>null</code>&gt;</p></blockquote><p>Given a bare skill id, return the highest-priority <code>SkillRef</code> that holds it, or <code>null</code> if no root has the id.</p><h4 id="parameters-4" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-4" aria-label="Permalink to &quot;Parameters&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Parameter</th><th>Type</th></tr></thead><tbody><tr><td><code>id</code></td><td><code>string</code></td></tr></tbody></table><h4 id="returns-5" tabindex="-1">Returns <a class="header-anchor" href="#returns-5" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>Promise</code>&lt;<a href="./SkillRef.html"><code>SkillRef</code></a> | <code>null</code>&gt;</p><hr><h3 id="subscribe" tabindex="-1">subscribe()? <a class="header-anchor" href="#subscribe" aria-label="Permalink to &quot;subscribe()?&quot;">​</a></h3><blockquote><p><code>optional</code> <strong>subscribe</strong>(<code>listener</code>): () =&gt; <code>void</code></p></blockquote><p>Optional change notification. Mutating implementations should fire the listener after a change is observable via <code>listSkills</code>/<code>readSkill</code>. Read-only storages may omit this; consumers must guard with <code>storage.subscribe?.(listener)</code>.</p><h4 id="parameters-5" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-5" aria-label="Permalink to &quot;Parameters&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Parameter</th><th>Type</th></tr></thead><tbody><tr><td><code>listener</code></td><td>() =&gt; <code>void</code></td></tr></tbody></table><h4 id="returns-6" tabindex="-1">Returns <a class="header-anchor" href="#returns-6" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p>() =&gt; <code>void</code></p>',69)])])}const b=t(l,[["render",d]]);export{k as __pageData,b as default};
